import{_ as e,o as l,c as a,a2 as i}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"F04: 業外收支純度與收益質量","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6442_光聖/20260504/F04_業外收支純度與收益質量.md","filePath":"審計報告庫/財務審計/6442_光聖/20260504/F04_業外收支純度與收益質量.md"}'),r={name:"審計報告庫/財務審計/6442_光聖/20260504/F04_業外收支純度與收益質量.md"};function n(s,t,d,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="f04-業外收支純度與收益質量" tabindex="-1">F04: 業外收支純度與收益質量 <a class="header-anchor" href="#f04-業外收支純度與收益質量" aria-label="Permalink to &quot;F04: 業外收支純度與收益質量&quot;">​</a></h1><blockquote><p>標的公司：6442 光聖 | 基準日期：20260504</p></blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><hr><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>業外收支規模與組成細項為何？是長期投資收益還是匯兌/利息等雜項損益？是否存在獲利虛胖風險？</p><hr><h2 id="🎯-專家直斷-40-80-字" tabindex="-1">🎯 專家直斷（40-80 字） <a class="header-anchor" href="#🎯-專家直斷-40-80-字" aria-label="Permalink to &quot;🎯 專家直斷（40-80 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：業外淨損1.61億壓低獲利本業&gt;100%。匯兌主因。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：25年報</li></ul><hr><h2 id="📊-診斷評級-80-150-字" tabindex="-1">📊 診斷評級（80-150 字） <a class="header-anchor" href="#📊-診斷評級-80-150-字" aria-label="Permalink to &quot;📊 診斷評級（80-150 字）&quot;">​</a></h2><p>業外收支 -1.61 億（佔稅前 -6.8%），為淨費用。主因為匯兌方向反轉——2024 年利益 1.23 億→2025 年損失 1.65 億。本業營收貢獻度 &gt;100%，收益質量極佳。</p><p><strong>評級：S（優）</strong> — 業外為淨費用，本業獲利佔比 &gt;100%。</p><hr><h2 id="🔍-答詢詳解-200-450-字" tabindex="-1">🔍 答詢詳解（200-450 字） <a class="header-anchor" href="#🔍-答詢詳解-200-450-字" aria-label="Permalink to &quot;🔍 答詢詳解（200-450 字）&quot;">​</a></h2><h3 id="_1-收益結構透視-income-composition" tabindex="-1">1. 收益結構透視（Income Composition） <a class="header-anchor" href="#_1-收益結構透視-income-composition" aria-label="Permalink to &quot;1. 收益結構透視（Income Composition）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">業外科目</th><th style="text-align:right;">2025（千元）</th><th style="text-align:left;">佔比</th><th style="text-align:right;">2024（千元）</th><th style="text-align:left;">佔比</th></tr></thead><tbody><tr><td style="text-align:left;">本業營業利益</td><td style="text-align:right;">2,538,981</td><td style="text-align:left;">106.8%</td><td style="text-align:right;">1,294,608</td><td style="text-align:left;">91.0%</td></tr><tr><td style="text-align:left;">＋利息收入</td><td style="text-align:right;">84,388</td><td style="text-align:left;">3.5%</td><td style="text-align:right;">35,461</td><td style="text-align:left;">2.5%</td></tr><tr><td style="text-align:left;">＋匯兌損益</td><td style="text-align:right;">(164,895)</td><td style="text-align:left;">−6.9%</td><td style="text-align:right;">122,950</td><td style="text-align:left;">8.6%</td></tr><tr><td style="text-align:left;">＋金融資產評價</td><td style="text-align:right;">(21,185)</td><td style="text-align:left;">−0.9%</td><td style="text-align:right;">3,300</td><td style="text-align:left;">0.2%</td></tr><tr><td style="text-align:left;">−財務成本</td><td style="text-align:right;">(36,774)</td><td style="text-align:left;">−1.5%</td><td style="text-align:right;">(14,753)</td><td style="text-align:left;">−1.0%</td></tr><tr><td style="text-align:left;">−權益法損失</td><td style="text-align:right;">(25,208)</td><td style="text-align:left;">−1.1%</td><td style="text-align:right;">(16,202)</td><td style="text-align:left;">−1.1%</td></tr><tr><td style="text-align:left;"><strong>稅前淨利</strong></td><td style="text-align:right;"><strong>2,378,298</strong></td><td style="text-align:left;"><strong>100%</strong></td><td style="text-align:right;"><strong>1,422,286</strong></td><td style="text-align:left;"><strong>100%</strong></td></tr></tbody></table><p><strong>關鍵判讀</strong>：純本業獲利 25.39 億超越稅前 23.78 億，本業貢獻度 106.8%。業外壓低帳面獲利，是最理想的收益結構。</p><h3 id="_2-匯兌敏感度分析-noise-sensitivity" tabindex="-1">2. 匯兌敏感度分析（Noise Sensitivity） <a class="header-anchor" href="#_2-匯兌敏感度分析-noise-sensitivity" aria-label="Permalink to &quot;2. 匯兌敏感度分析（Noise Sensitivity）&quot;">​</a></h3><p>2025 年匯兌損失 1.65 億（2024 年利益 1.23 億），兩年反彈差 2.88 億。營收 63% 以美元計價，但生產跨台灣、中國、菲律賓，天然避險但非完全對沖。若台股升值 3%，匯兌損失將增約相同規模。</p><h3 id="_3-可持續性評價-sustainability-audit" tabindex="-1">3. 可持續性評價（Sustainability Audit） <a class="header-anchor" href="#_3-可持續性評價-sustainability-audit" aria-label="Permalink to &quot;3. 可持續性評價（Sustainability Audit）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">業外項目</th><th style="text-align:right;">可持續性</th></tr></thead><tbody><tr><td style="text-align:left;">利息收入</td><td style="text-align:right;">穩定增長，隨 74.9 億現金水位上升</td></tr><tr><td style="text-align:left;">匯兌損益</td><td style="text-align:right;">隨機波動，零可預測性</td></tr><tr><td style="text-align:left;">財務成本</td><td style="text-align:right;">結構性上升，CB 利息 2,145 萬</td></tr><tr><td style="text-align:left;">權益法損失</td><td style="text-align:right;">穩定微損，影響可忽略</td></tr></tbody></table><p>利息收入為最穩定正貢獻（2025 年 0.84 億），2026 年有望突破 1.2 億。</p><hr><h2 id="💡-專家評析-200-450-字" tabindex="-1">💡 專家評析（200-450 字） <a class="header-anchor" href="#💡-專家評析-200-450-字" aria-label="Permalink to &quot;💡 專家評析（200-450 字）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><p><strong>匯兌損失波動風險顯著</strong>：2025 年匯兌損失 1.65 億 vs 2024 年利益 1.23 億，差距 2.88 億影響 EPS 約 3.8 元。光聖未使用匯率衍生性商品避險，外幣曝險裸露程度高。</p></li><li><p><strong>CB 利息成本擴張</strong>：CB 利息 2,145 萬（年增 620%），未被轉換將持續壓縮獲利空間。</p></li><li><p><strong>金融資產評價損失波動</strong>：2025 年損失 2,118 萬，市場惡化時可擴大至 5,000 萬以上。</p></li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><p><strong>本業純度 &gt;100%，無獲利虛胖</strong>：業外為淨費用，剔除後仍高於帳面數字。</p></li><li><p><strong>利息收入穩定成長</strong>：現金 74.9 億，保守計算 2026 年利息可達 1.12 億。</p></li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>光聖業外屬淨抑制因素，品質頂尖。匯兌波動相對於本業 25.4 億營利影響可控。需跟蹤 CB 利息與轉換進度。</p><hr><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>原始數據</strong>：FinMind TaiwanStockFinancialStatements（TotalNonoperatingIncomeAndExpense / OperatingIncome / PreTaxIncome）</li><li><strong>年報資料</strong>：6442 2025 Q4 合併財報第 9 頁（綜合損益表）及第 50 頁（業外明細附註二四）</li><li><strong>查詢參數</strong>：stock_id=6442, start=2023-01-01, end=2025-12-31</li><li><strong>數據查詢日期</strong>：2026-05-04</li></ul>',34)])])}const c=e(r,[["render",n]]);export{y as __pageData,c as default};
